    const uint32_t inFeatures = static_cast<uint32_t>(xShape.GetDim(1));
    const uint32_t outFeatures = static_cast<uint32_t>(wShape.GetDim(0));
    const uint32_t totalLength = batchSize * outFeatures;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *numGroupsPtr = attrs->GetAttrPointer<int64_t>(0);
    const float *epsilonPtr = attrs->GetAttrPointer<float>(1);
